package com.criteo.api.sdk.gradle

import org.gradle.api.Project
import org.gradle.api.Plugin
import com.criteo.api.sdk.gradle.tasks.GenerateSdkTask

class CriteoApiSdkGeneratorPlugin: Plugin<Project> {
    override fun apply(project: Project) {
        project.run {   
            tasks.apply {
                register("greeting") { task ->
                    task.doLast {
                        println("Hello from plugin 'com.criteo.api.sdk.gradle.greeting'")
                    }
                }
                register("generateSdk", GenerateSdkTask::class.java).configure {
                }
            }
        }
    }
}
